import React, { useEffect, useState } from "react";
import api from "../api";
import ItemCard from "../components/ItemCard";

function Dashboard() {
  const [items, setItems] = useState([]);
  const [keyword, setKeyword] = useState("");
  const [category, setCategory] = useState("");
  const [location, setLocation] = useState("");
  const [status, setStatus] = useState("");
  const [viewMode, setViewMode] = useState("cards");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [dashboard, setDashboard] = useState({ lostCount: 0, foundCount: 0, latestItems: [] });

  const loadItems = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await api.get("/items");
      setItems(response.data);
    } catch (err) {
      setError("Failed to load items. Please check backend.");
    } finally {
      setLoading(false);
    }
  };

  const loadDashboard = async () => {
    setError("");
    try {
      const response = await api.get("/items/dashboard");
      setDashboard(response.data);
    } catch (err) {
      setError("Failed to load dashboard stats.");
    }
  };

  useEffect(() => {
    loadItems();
    loadDashboard();
  }, []);

  const handleSearch = async (e) => {
    if (e) {
      e.preventDefault();
    }
    setLoading(true);
    setError("");
    try {
      const response = await api.get(`/items/search?keyword=${encodeURIComponent(keyword)}`);
      setItems(response.data);
    } catch (err) {
      setError("Search request failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleFilter = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await api.get(
        `/items/filter?category=${encodeURIComponent(category)}&location=${encodeURIComponent(location)}&status=${encodeURIComponent(status)}`
      );
      setItems(response.data);
    } catch (err) {
      setError("Filter request failed.");
    } finally {
      setLoading(false);
    }
  };

  const totalItems = items.length;
  const claimedCount = items.filter((item) => item.status === "CLAIMED" || item.status === "RETURNED").length;

  const resetAll = () => {
    setKeyword("");
    setCategory("");
    setLocation("");
    setStatus("");
    loadItems();
  };

  return (
    <div className="dashboard-page">
      <section className="widget-grid">
        <div className="widget widget-blue">
          <h4>Total Items</h4>
          <p>{totalItems}</p>
        </div>
        <div className="widget widget-red">
          <h4>Lost Items</h4>
          <p>{dashboard.lostCount}</p>
        </div>
        <div className="widget widget-green">
          <h4>Found Items</h4>
          <p>{dashboard.foundCount}</p>
        </div>
        <div className="widget widget-amber">
          <h4>Resolved Items</h4>
          <p>{claimedCount}</p>
        </div>
      </section>

      <section className="panel">
        <div className="panel-title-row">
          <h3>Item Operations</h3>
          <div className="view-toggle">
            <button
              type="button"
              className={viewMode === "cards" ? "active" : ""}
              onClick={() => setViewMode("cards")}
            >
              Card View
            </button>
            <button
              type="button"
              className={viewMode === "table" ? "active" : ""}
              onClick={() => setViewMode("table")}
            >
              Table View
            </button>
          </div>
        </div>

        <form className="filter-row" onSubmit={handleSearch}>
          <input
            placeholder="Search by title"
            value={keyword}
            onChange={(e) => setKeyword(e.target.value)}
          />
          <input
            placeholder="Category"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
          />
          <input
            placeholder="Location"
            value={location}
            onChange={(e) => setLocation(e.target.value)}
          />
          <select value={status} onChange={(e) => setStatus(e.target.value)}>
            <option value="">All Status</option>
            <option value="LOST">LOST</option>
            <option value="FOUND">FOUND</option>
            <option value="CLAIMED">CLAIMED</option>
            <option value="RETURNED">RETURNED</option>
            <option value="EXPIRED">EXPIRED</option>
          </select>
          <button type="submit">Search</button>
          <button type="button" onClick={handleFilter}>Apply Filter</button>
          <button type="button" className="ghost-btn" onClick={resetAll}>Reset</button>
        </form>

        {error ? <p className="error-text">{error}</p> : null}
        {loading ? <p className="helper-text">Loading records...</p> : null}
      </section>

      <section className="panel">
        <h3>Latest Items</h3>
        <div className="item-grid">
          {dashboard.latestItems && dashboard.latestItems.map((item) => (
            <ItemCard key={item.id} item={item} />
          ))}
        </div>
      </section>

      <section className="panel">
        <h3>All Items</h3>
        {viewMode === "cards" ? (
          <div className="item-grid">
            {items.map((item) => (
              <ItemCard key={item.id} item={item} />
            ))}
          </div>
        ) : (
          <div className="table-wrap">
            <table className="item-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Title</th>
                  <th>Category</th>
                  <th>Location</th>
                  <th>Status</th>
                  <th>Contact</th>
                </tr>
              </thead>
              <tbody>
                {items.map((item) => (
                  <tr key={item.id}>
                    <td>{item.id}</td>
                    <td>{item.title}</td>
                    <td>{item.category}</td>
                    <td>{item.location}</td>
                    <td>{item.status}</td>
                    <td>{item.contactInfo}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </div>
  );
}

export default Dashboard;
